mapper.sql:
where status = 1
  and job_description is not null
  and trim(job_description) != ''

    and (
        job_title like concat('%', #{keyword}, '%')
        or company_name like concat('%', #{keyword}, '%')
        or work_address like concat('%', #{keyword}, '%')
        or job_description like concat('%', #{keyword}, '%')
    )


    and city = #{city}


    and education_text = #{educationText}


    and experience_text = #{experienceText}


    and salary_max is not null
    and salary_max >= #{salaryMin}


    and salary_min is not null
    and salary_min <= #{salaryMax}


    and salary_min is not null
    and salary_max is not null
